import { Component, OnInit, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { AuthService } from '../../../core/services/auth.service';
import { UserProfile } from '../../../core/models/user-profile.model';

@Component({
  selector: 'app-perfil',
  standalone: true,
  imports: [CommonModule],
  templateUrl: './perfil.component.html',
  styleUrls: ['./perfil.component.css']
})
export class PerfilComponent implements OnInit {
  private authService = inject(AuthService);

  profile: UserProfile | null = null;
  isLoading = true;

  ngOnInit(): void {
    this.authService.getProfile().subscribe({
      next: (data) => {
        this.profile = data;
        this.isLoading = false;
      },
      error: (err) => {
        console.error('Error fetching user profile:', err);
        this.isLoading = false;
      }
    });
  }
}
<div class="space-y-8 font-body" *ngIf="profile">

  <!-- Banner Header -->
  <div class="border border-slate-200 p-8 bg-white rounded-none shadow-[4px_4px_0px_0px_rgba(15,23,42,0.05)]">
    <h1 class="text-2xl font-black text-slate-900 tracking-tight uppercase leading-none">Mi Perfil</h1>
    <p class="text-slate-500 text-xs mt-2">Revisa y administra los datos de tu cuenta personal y el estado de tu suscripción actual.</p>
  </div>

  <div class="grid grid-cols-1 lg:grid-cols-3 gap-8">

    <!-- User Info Card -->
    <div class="lg:col-span-2 border border-slate-200 bg-white p-8 rounded-none shadow-[4px_4px_0px_0px_rgba(15,23,42,0.05)]">
      <h2 class="text-sm font-black text-slate-900 uppercase tracking-wider mb-6 border-b border-slate-100 pb-3">Información Personal</h2>

      <div class="grid grid-cols-1 md:grid-cols-2 gap-6 text-xs">
        <div>
          <label class="block text-[9px] font-bold text-slate-400 uppercase tracking-widest mb-1">Nombre Completo</label>
          <div class="px-4 py-3 bg-slate-50 border border-slate-200 text-slate-800 font-bold uppercase">
            {{ profile.nombres }} {{ profile.apellidos }}
          </div>
        </div>

        <div>
          <label class="block text-[9px] font-bold text-slate-400 uppercase tracking-widest mb-1">Correo Electrónico</label>
          <div class="px-4 py-3 bg-slate-50 border border-slate-200 text-slate-800 font-bold">
            {{ profile.correo }}
          </div>
        </div>

        <div>
          <label class="block text-[9px] font-bold text-slate-400 uppercase tracking-widest mb-1">Rol de Acceso</label>
          <div class="px-4 py-3 bg-slate-50 border border-slate-200 text-primary font-bold uppercase tracking-wider">
            {{ profile.rol }}
          </div>
        </div>

        <div>
          <label class="block text-[9px] font-bold text-slate-400 uppercase tracking-widest mb-1">Identificador Único</label>
          <div class="px-4 py-3 bg-slate-50 border border-slate-200 text-slate-500 font-mono">
            USR-{{ profile.id }}
          </div>
        </div>
      </div>
    </div>

    <!-- Suscripcion status card -->
    <div class="border border-slate-200 bg-white p-8 rounded-none shadow-[4px_4px_0px_0px_rgba(15,23,42,0.05)]">
      <h2 class="text-sm font-black text-slate-900 uppercase tracking-wider mb-6 border-b border-slate-100 pb-3">Suscripción</h2>

      <div class="text-center py-6">
        <span class="material-symbols-outlined text-5xl text-slate-400">workspace_premium</span>
        <h3 class="text-lg font-black text-slate-900 uppercase mt-4 tracking-tight">Acceso Campus</h3>

        <div class="inline-block mt-3 px-4 py-1.5 bg-slate-900 text-white border border-slate-900 text-[10px] font-black uppercase tracking-widest rounded-none shadow-[2px_2px_0px_0px_rgba(0,0,0,0.15)]">
          Plan Vigente
        </div>

        <p class="text-slate-500 text-xs mt-4 leading-relaxed">
          Tu cuenta está autorizada para consumir todo el material académico disponible según tu nivel de suscripción.
        </p>
      </div>
    </div>

  </div>

</div>
